#include <stdio.h>
#include <string.h>
int main() {
    int n;
    char s[101];
    scanf("%d", &n);
    scanf("%s", s);
    int ans = n + 1;
    for (int i = 0; i < n; i++) {
        int cnt[26] = {0};
        for (int j = i; j < n; j++) {
            cnt[s[j] - 'a']++;
            int tot = 0;
            for (int k = 0; k < 4; k++) {
                if (cnt[k] > 0) tot++;
            }
            if (tot == 4) {
                ans = (j - i + 1) < ans ? (j - i + 1) : ans;
            }
        }
    }
    if (ans == n + 1) printf("-1");
    else printf("%d", ans);
    return 0;
}

